pair A, B, C, D;

B = (0,0);
C = (8,0);
A = intersectionpoint(arc(B,3,0,180),arc(C,6,0,180));
D = interp(B,C,3/9);

draw(A--B--C--cycle);
draw(A--D);

label("$A$", A, N);
label("$B$", B, SW);
label("$C$", C, SE);
label("$D$", D, S);
[/asy]

